import subprocess

def install_dependencies():
    print("Installing dependencies...")
    subprocess.check_call(['pip', 'install', '-r', 'requirements.txt'])
    print("Dependencies installed successfully.")

def run_tests():
    print("Running tests...")
    test_result = subprocess.run(['pytest'], capture_output=True, text=True)
    if "All tests passed" in test_result.stdout:
        print(f"Test results:\n{test_result.stdout}")
        return True
    else:
        print(f"Tests failed:\n{test_result.stderr}\n")
        raise Exception("Tests Failed")

def package_project():
    print("Packaging the project...")
    subprocess.check_call(['python', 'setup.py', 'sdist', 'bdist_wheel'])
    print("Project packaged successfully.")

if __name__ == "__main__":
    install_dependencies()
    if run_tests():
        package_project()